import { useEffect, useState } from 'react';
import { collection, getDocs } from 'firebase/firestore';
import { db } from '../services/firebase';

export default function TestFirebase() {
  const [data, setData] = useState<any[]>([]);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        console.log('Начало запроса к Firestore...'); // Лог 1
        const querySnapshot = await getDocs(collection(db, 'test_activities'));
        console.log('Запрос выполнен, документов:', querySnapshot.size); // Лог 2
        
        if (querySnapshot.empty) {
          setError('Коллекция пуста. Добавьте данные в Firestore.');
        } else {
          const docs = querySnapshot.docs.map(doc => doc.data());
          setData(docs);
        }
      } catch (err) {
        console.error('Ошибка Firestore:', err); // Лог 3
        setError('Ошибка подключения к Firebase');
      }
    };

    fetchData();
  }, []);

  return (
    <div>
      <h3>Тест Firebase</h3>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {data.length > 0 && (
        <ul>
          {data.map((item, index) => (
            <li key={index}>{JSON.stringify(item)}</li>
          ))}
        </ul>
      )}
      {!error && data.length === 0 && <p>Загрузка данных...</p>}
    </div>
  );
}
